async function handleRequest(request) {
  const url = new URL(request.url);
  const ttl = url.searchParams.get('ttl') || 3600; // Default TTL to 1 hour
  const cacheKey = url.searchParams.get('cache_key') || request.url;

  const cache = caches.default;
  const cacheResponse = await cache.match(cacheKey);

  if (cacheResponse) {
    return cacheResponse;
  }

  const response = await fetch(request);

  if (response.ok) {
    const cacheControl = `public, max-age=${ttl}`;
    response.headers.append('Cache-Control', cacheControl);
    event.waitUntil(cache.put(cacheKey, response.clone()));
  }

  return response;
}